        _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

    var pipeline = _mlContext.Transforms.Text
            .FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject))
        .Append(_mlContext.Transforms.Text
            .FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
        .Append(_mlContext.Transforms.Concatenate("Features",
            "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
        .Append(_mlContext.Transforms.Conversion
            .MapValueToKey("Label", nameof(TicketInput.Category)))
        .Append(_mlContext.MulticlassClassification.Trainers
            .SdcaMaximumEntropy("Label", "Features"))
        .Append(_mlContext.Transforms.Conversion
            .MapKeyToValue("PredictedLabel"));

    // Use cross-validation for reliable metrics on small datasets
    var cvResults = _mlContext.MulticlassClassification.CrossValidate(
        data, pipeline, numberOfFolds: 3, labelColumnName: "Label");

    var avgMicro = cvResults.Average(r => r.Metrics.MicroAccuracy);
    var avgMacro = cvResults.Average(r => r.Metrics.MacroAccuracy);
    var avgLogLoss = cvResults.Average(r => r.Metrics.LogLoss);

    LastTrainingMetrics = new TrainingMetrics
    {
        MicroAccuracy = avgMicro,
        MacroAccuracy = avgMacro,
        LogLoss = avgLogLoss,
    };

    _logger.LogInformation(
        "Cross-validation ({Folds}-fold) — MicroAccuracy: {Micro:F4}, MacroAccuracy: {Macro:F4}, LogLoss: {LogLoss:F4}",
        cvResults.Length, avgMicro, avgMacro, avgLogLoss);

    // Train final model on full dataset
    var model = pipeline.Fit(data);
    _mlContext.Model.Save(model, data.Schema, _modelPath);
    _logger.LogInformation("Model saved to {Path}", _modelPath);
}

